solution:
class JavaScriptProgressiveWebApps {
  constructor(config) {
    this.config = config || {};
    this.data = [];
  }

  add(item) {
    if (item == null) throw new Error('Invalid item');
    this.data.push(item);
  }

  process() {
    return this.data
      .filter(d => d != null)
      .map(d => ({ value: d, timestamp: Date.now() }));
  }

  clear() {
    this.data = [];
  }
}

